220	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
221		if len(fields) == 0 {
222			return nil
223		}
224		seen := make(map[string]struct{}, len(fields))
225		out := make([]string, 0, len(fields))
226		for _, field := range fields {
227			field = strings.ToLower(strings.TrimSpace(field))
228			if field == "" {
229				continue
230			}
231			if _, ok := seen[field]; ok {
232				continue
233			}
234			seen[field] = struct{}{}
235			out = append(out, field)
236		}
237		return out
238	}
